14	
15	#![deny(warnings)]
16	#![allow(non_camel_case_types)]
17	#![allow(private_interfaces)]
18	#![cfg_attr(not(debug_assertions), windows_subsystem = "windows")]
19	
20	// RCG output discipline: all emission via apcrl_*! — no direct println!/eprintln!
21	
22	use std::sync::{Mutex, OnceLock};
23	use apcd::apcrm_match::{apcrm_Finding, apcrm_Severity, apcrm_PhiCategory};
24	
25	// ---------------------------------------------------------------------------
26	// Statics — dictionary cache, clipboard tracking, toggle state
27	// ---------------------------------------------------------------------------
28	
29	static ZAPCAP_DICTS: OnceLock<apcd::apcrd_dictionaries::apcrd_Dictionaries> = OnceLock::new();
30	static ZAPCAP_LAST_CLIPBOARD: Mutex<Option<String>> = Mutex::new(None);
31	static ZAPCAP_LAST_CLINICAL: Mutex<Option<zapcap_ClinicalCache>> = Mutex::new(None);
32	static ZAPCAP_TOGGLE_STATES: Mutex<Vec<String>> = Mutex::new(Vec::new());
33	
34	struct zapcap_ClinicalCache {
35	    findings:   Vec<apcrm_Finding>,
36	    plain_text: String,
37	}
38	
39	// ---------------------------------------------------------------------------
40	// Focus handler — read clipboard, run detection, push rendered HTML
41	// ---------------------------------------------------------------------------
42	
43	fn zapcap_handle_focus(window: &tauri::WebviewWindow) -> Result<(), String> {
44	    let mut clipboard = arboard::Clipboard::new()
45	        .map_err(|e| format!("clipboard error: {}", e))?;
46	
47	    let content = clipboard.get_text()
48	        .map_err(|e| format!("clipboard error: {}", e))?;
49	
50	    // Change detection — same content as last invocation → preserve UI state
51	    {
52	        let last = ZAPCAP_LAST_CLIPBOARD.lock()
53	            .map_err(|e| format!("lock error: {}", e))?;
54	        if last.as_deref() == Some(content.as_str()) {
55	            return Ok(());
56	        }
57	    }
58	
59	    let dicts = ZAPCAP_DICTS.get_or_init(apcd::apcrd_dictionaries::apcrd_Dictionaries::apcrd_load);
60	
61	    match apcd::apcre_engine::apcre_analyze(&content, dicts) {
62	        apcd::apcre_engine::apcre_Result::Clinical { findings, plain_text } => {
63	            // Clear system clipboard after consuming clinical content
64	            let _ = clipboard.set_text(String::new());
65	
66	            {
67	                let mut last = ZAPCAP_LAST_CLIPBOARD.lock()
68	                    .map_err(|e| format!("lock error: {}", e))?;
69	                *last = Some(String::new());
70	            }
71	
72	            {
73	                let mut toggle_states = ZAPCAP_TOGGLE_STATES.lock()
74	                    .map_err(|e| format!("lock error: {}", e))?;
75	                *toggle_states = vec!["elide".to_string(); findings.len()];
76	            }
77	
78	            {
79	                let mut cache = ZAPCAP_LAST_CLINICAL.lock()
80	                    .map_err(|e| format!("lock error: {}", e))?;
81	                *cache = Some(zapcap_ClinicalCache { findings, plain_text });
82	            }
83	
84	            zapcap_push_triage(window)
85	        }
86	        apcd::apcre_engine::apcre_Result::NonClinical { content_length, content_type, preview } => {
87	            {
88	                let mut last = ZAPCAP_LAST_CLIPBOARD.lock()
89	                    .map_err(|e| format!("lock error: {}", e))?;
90	                *last = Some(content);
91	            }
92	
93	            {
94	                let mut cache = ZAPCAP_LAST_CLINICAL.lock()
95	                    .map_err(|e| format!("lock error: {}", e))?;
96	                *cache = None;
97	            }
98	
99	            {
100	                let mut toggle_states = ZAPCAP_TOGGLE_STATES.lock()
101	                    .map_err(|e| format!("lock error: {}", e))?;
102	                *toggle_states = Vec::new();
103	            }
104	
105	            let diagnostic = format!(
106	                "Not clinical ({} bytes, {}): {}",
107	                content_length, content_type, preview
108	            );
109	            zapcap_push_instruction(window, &diagnostic)
110	        }
111	    }
112	}
113	
114	// ---------------------------------------------------------------------------
115	// Tauri commands — toggle finding, copy anonymized
116	// ---------------------------------------------------------------------------
117	
118	#[tauri::command]
119	fn toggle_finding(index: usize, window: tauri::WebviewWindow) -> Result<(), String> {
120	    {
121	        let mut states = ZAPCAP_TOGGLE_STATES.lock()
122	            .map_err(|e| format!("lock error: {}", e))?;
123	        if index < states.len() {
124	            states[index] = if states[index] == "elide" {
125	                "pass".to_string()
126	            } else {
127	                "elide".to_string()
128	            };
129	        }
130	    }
131	    zapcap_push_triage(&window)
132	}
133	
134	#[tauri::command]
135	fn copy_anonymized(window: tauri::WebviewWindow) -> Result<(), String> {
136	    let toggle_states = ZAPCAP_TOGGLE_STATES.lock()
137	        .map_err(|e| format!("lock error: {}", e))?
138	        .clone();
139	
140	    let anonymized = {
141	        let cache = ZAPCAP_LAST_CLINICAL.lock()
142	            .map_err(|e| format!("lock error: {}", e))?;
143	        let clinical = cache.as_ref()
144	            .ok_or_else(|| "no clinical data to anonymize".to_string())?;
145	        apcd::apcre_engine::apcre_anonymize(
146	            &clinical.plain_text,
147	            &clinical.findings,
148	            &toggle_states,
149	        )
150	    };
151	
152	    let mut clipboard = arboard::Clipboard::new()
153	        .map_err(|e| format!("clipboard error: {}", e))?;
154	    clipboard.set_text(anonymized)
155	        .map_err(|e| format!("clipboard error: {}", e))?;
156	
157	    zapcap_push_triage_with_feedback(&window, "Copied!")?;
158	
159	    let win = window.clone();
160	    std::thread::spawn(move || {
161	        std::thread::sleep(std::time::Duration::from_secs(2));
162	        let _ = zapcap_push_triage(&win);
163	    });
164	
165	    Ok(())
166	}
167	
168	// ---------------------------------------------------------------------------
169	// HTML push — render state and inject into webview
170	// ---------------------------------------------------------------------------
171	
172	fn zapcap_push_instruction(window: &tauri::WebviewWindow, diagnostic: &str) -> Result<(), String> {
173	    let html = zapcap_render_instruction(diagnostic);
174	    zapcap_eval_html(window, &html)
175	}
176	
177	fn zapcap_push_triage(window: &tauri::WebviewWindow) -> Result<(), String> {
178	    zapcap_push_triage_with_feedback(window, "Copy Anonymized to Clipboard")
179	}
180	
181	fn zapcap_push_triage_with_feedback(
182	    window: &tauri::WebviewWindow,
183	    btn_text: &str,
184	) -> Result<(), String> {
185	    // Clone data out of locks to avoid holding multiple locks simultaneously
186	    let (findings, plain_text) = {
187	        let cache = ZAPCAP_LAST_CLINICAL.lock()
188	            .map_err(|e| format!("lock error: {}", e))?;
189	        let clinical = cache.as_ref()
190	            .ok_or_else(|| "no clinical data for triage".to_string())?;
191	        (clinical.findings.clone(), clinical.plain_text.clone())
192	    };
193	    let toggle_states = ZAPCAP_TOGGLE_STATES.lock()
194	        .map_err(|e| format!("lock error: {}", e))?
195	        .clone();
196	
197	    let html = zapcap_render_triage(&findings, &plain_text, &toggle_states, btn_text);
198	    zapcap_eval_html(window, &html)
199	}
200	
201	fn zapcap_eval_html(window: &tauri::WebviewWindow, html: &str) -> Result<(), String> {
202	    let escaped = zapcap_js_string_literal(html);
203	    window.eval(&format!("document.getElementById('app').innerHTML={}", escaped))
204	        .map_err(|e| format!("eval error: {}", e))
205	}
206	
207	// ---------------------------------------------------------------------------
208	// HTML rendering — instruction state
209	// ---------------------------------------------------------------------------
210	
211	fn zapcap_render_instruction(diagnostic: &str) -> String {
212	    format!(
213	        "<h1>Ann&rsquo;s PHI Clipbuddy</h1>\
214	         <p class=\"instruction\">Copy a clinical note from Epic using \
215	         &ldquo;Copy All&rdquo;, then switch to this window.</p>\
216	         <p class=\"diagnostic\">{}</p>",
217	        zapcap_escape_html(diagnostic)
218	    )
219	}
220	
221	// ---------------------------------------------------------------------------
222	// HTML rendering — triage state
223	// ---------------------------------------------------------------------------
224	
225	fn zapcap_render_triage(
226	    findings: &[apcrm_Finding],
227	    plain_text: &str,
228	    toggle_states: &[String],
229	    btn_text: &str,
230	) -> String {
231	    let preview = zapcap_render_preview(findings, plain_text, toggle_states);
232	    let (yellow_html, red_html) = zapcap_render_findings(findings, toggle_states);
233	
234	    format!(
235	        "<h1>Ann&rsquo;s PHI Clipbuddy</h1>\
236	         <div id=\"document-preview\">{}</div>\
237	         <div id=\"findings-panel\">\
238	         <div class=\"findings-section\" id=\"findings-yellow\">\
239	         <h3>Questionable Findings</h3>\
240	         <div class=\"findings-list\" id=\"yellow-list\">{}</div></div>\
241	         <div class=\"findings-section\" id=\"findings-red\">\
242	         <h3>Definite PHI</h3>\
243	         <div class=\"findings-list\" id=\"red-list\">{}</div></div></div>\
244	         <button id=\"copy-btn\" \
245	         onclick=\"window.__TAURI__.core.invoke('copy_anonymized')\">{}</button>",
246	        preview, yellow_html, red_html, zapcap_escape_html(btn_text)
247	    )
248	}
249	
250	// ---------------------------------------------------------------------------
251	// HTML rendering — document preview with inline PHI highlights
252	// ---------------------------------------------------------------------------
253	
254	fn zapcap_render_preview(
255	    findings: &[apcrm_Finding],
256	    plain_text: &str,
257	    toggle_states: &[String],
258	) -> String {
259	    // Build index-annotated list sorted by offset (byte offsets used directly)
260	    let mut sorted: Vec<(usize, &apcrm_Finding)> = findings.iter().enumerate().collect();
261	    sorted.sort_by(|a, b| a.1.offset.cmp(&b.1.offset).then(b.1.length.cmp(&a.1.length)));
262	
263	    let mut parts = Vec::new();
264	    let mut pos: usize = 0;
265	
266	    for (idx, f) in &sorted {
267	        if f.offset < pos { continue; } // skip overlap
268	
269	        // Text before this finding
270	        if f.offset > pos {
271	            parts.push(zapcap_escape_html(&plain_text[pos..f.offset]));
272	        }
273	
274	        // Finding span — byte offsets consumed directly, no conversion needed
275	        let end = f.offset + f.length;
276	        let cls = if toggle_states.get(*idx).map(|s| s.as_str()) == Some("pass") {
277	            "phi-pass"
278	        } else if f.severity == apcrm_Severity::Red {
279	            "phi-red"
280	        } else {
281	            "phi-yellow"
282	        };
283	
284	        parts.push(format!(
285	            "<span class=\"{}\" data-index=\"{}\">{}</span>",
286	            cls, idx, zapcap_escape_html(&plain_text[f.offset..end])
287	        ));
288	        pos = end;
289	    }
290	
291	    // Remaining text
292	    if pos < plain_text.len() {
293	        parts.push(zapcap_escape_html(&plain_text[pos..]));
294	    }
295	
296	    parts.join("")
297	}
298	
299	// ---------------------------------------------------------------------------
300	// HTML rendering — findings panel (yellow + red sections)
301	// ---------------------------------------------------------------------------
302	
303	fn zapcap_render_findings(
304	    findings: &[apcrm_Finding],
305	    toggle_states: &[String],
306	) -> (String, String) {
307	    let mut yellow = Vec::new();
308	    let mut red = Vec::new();
309	
310	    for (i, f) in findings.iter().enumerate() {
311	        let state = toggle_states.get(i).map(|s| s.as_str()).unwrap_or("elide");
312	        let label = zapcap_format_category(f.category);
313	        let btn_text = if state == "elide" { "ELIDE \u{25bc}" } else { "PASS \u{25bc}" };
314	
315	        let entry = format!(
316	            "<div class=\"finding-entry\">\
317	             <span class=\"finding-text\">{}</span>\
318	             <span class=\"finding-category\">{}</span>\
319	             <button class=\"finding-toggle {}\" \
320	             onclick=\"window.__TAURI__.core.invoke('toggle_finding',{{index:{}}})\"\
321	             >{}</button></div>",
322	            zapcap_escape_html(&f.text),
323	            label,
324	            state,
325	            i,
326	            btn_text
327	        );
328	
329	        if f.severity == apcrm_Severity::Yellow {
330	            yellow.push(entry);
331	        } else {
332	            red.push(entry);
333	        }
334	    }
335	
336	    let yellow_html = if yellow.is_empty() {
337	        "<div class=\"empty-section\">None detected</div>".to_string()
338	    } else {
339	        yellow.join("")
340	    };
341	
342	    let red_html = if red.is_empty() {
343	        "<div class=\"empty-section\">None detected</div>".to_string()
344	    } else {
345	        red.join("")
346	    };
347	
348	    (yellow_html, red_html)
349	}
350	
351	// ---------------------------------------------------------------------------
352	// Utilities
353	// ---------------------------------------------------------------------------
354	
355	fn zapcap_format_category(cat: apcrm_PhiCategory) -> &'static str {
356	    match cat {
357	        apcrm_PhiCategory::Name         => "NAME",
358	        apcrm_PhiCategory::Provider     => "PROVIDER",
359	        apcrm_PhiCategory::Facility     => "FACILITY",
360	        apcrm_PhiCategory::Date         => "DATE",
361	        apcrm_PhiCategory::Dob          => "DOB",
362	        apcrm_PhiCategory::Phone        => "PHONE",
363	        apcrm_PhiCategory::Email        => "EMAIL",
364	        apcrm_PhiCategory::Ssn          => "SSN",
365	        apcrm_PhiCategory::Mrn          => "MRN",
366	        apcrm_PhiCategory::Account      => "ACCOUNT",
367	        apcrm_PhiCategory::EncounterId  => "ENCOUNTER ID",
368	        apcrm_PhiCategory::Address      => "ADDRESS",
369	        apcrm_PhiCategory::HealthPlanId => "HEALTH PLAN ID",
370	        apcrm_PhiCategory::DeviceId     => "DEVICE ID",
371	        apcrm_PhiCategory::Npi          => "NPI",
372	        apcrm_PhiCategory::Dea          => "DEA",
373	        apcrm_PhiCategory::Url          => "URL",
374	        apcrm_PhiCategory::IpAddress    => "IP ADDRESS",
375	    }
376	}
377	
378	fn zapcap_escape_html(text: &str) -> String {
379	    text.replace('&', "&amp;")
380	        .replace('<', "&lt;")
381	        .replace('>', "&gt;")
382	        .replace('"', "&quot;")
383	}
384	
385	fn zapcap_js_string_literal(s: &str) -> String {
386	    let mut out = String::with_capacity(s.len() + 2);
387	    out.push('"');
388	    for c in s.chars() {
389	        match c {
390	            '\\'     => out.push_str("\\\\"),
391	            '"'      => out.push_str("\\\""),
392	            '\n'     => out.push_str("\\n"),
393	            '\r'     => out.push_str("\\r"),
394	            '\t'     => out.push_str("\\t"),
395	            '\u{08}' => out.push_str("\\b"),
396	            '\u{0C}' => out.push_str("\\f"),
397	            '\u{2028}' => out.push_str("\\u2028"),
398	            '\u{2029}' => out.push_str("\\u2029"),
399	            c if (c as u32) < 0x20 => out.push_str(&format!("\\u{:04x}", c as u32)),
400	            c => out.push(c),
401	        }
402	    }
403	    out.push('"');
404	    out
405	}
406	
407	// ---------------------------------------------------------------------------
408	// Entry point
409	// ---------------------------------------------------------------------------
410	
411	fn main() {
412	    apcd::apcrl_info_now!("starting Ann's PHI Clipbuddy");
413	    apcd::apcru_update::apcru_start_watcher();
414	    tauri::Builder::default()
415	        .invoke_handler(tauri::generate_handler![toggle_finding, copy_anonymized])
416	        .setup(|app| {
417	            use tauri::Manager;
418	            let window = app.get_webview_window("main")
419	                .expect("main window must exist");
420	            let win = window.clone();
421	            window.on_window_event(move |event| {
422	                if let tauri::WindowEvent::Focused(true) = event {
423	                    if let Err(e) = zapcap_handle_focus(&win) {
424	                        apcd::apcrl_error_now!("focus handler error: {}", e);
425	                    }
426	                }
427	            });
428	            Ok(())
429	        })
430	        .run(tauri::generate_context!())
431	        .unwrap_or_else(|e| apcd::apcrl_fatal_now!("tauri application error: {}", e));
432	}
433

