66	#[macro_export] macro_rules! apcrl_trace_if {
67	    ($cond:expr, $($arg:tt)*) => {{ let z = $cond; if z { $crate::apcrl_log::zapcrl_emit($crate::apcrl_log::APCRL_LEVEL_TRACE, file!(), line!(), &format!($($arg)*)); } z }};
68	}
69	#[macro_export] macro_rules! apcrl_error_if {
